module counter_8bit(obf_clk, rst, en, count);
    input obf_clk;
    input rst;
    input en;
    output reg [7:0] count;

    always @(posedge obf_clk or posedge rst) begin
        if (rst) begin
            count <= 0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
